```python
def is_sorted(lst):
    # Handle empty list or single element
    if len(lst) <= 1:
        return True

    # Check for duplicates - count occurrences of each number
    from collections import Counter
    counts = Counter(lst)
    for count in counts.values():
        if count > 2:
            return False

    # Check if list is sorted in ascending order
    for i in range(1, len(lst)):
        if lst[i] < lst[i-1]:
            return False

    return True
```

