```python
def flip_case(string: str) -> str:
    """
    Flip lowercase characters to uppercase and uppercase to lowercase.

    Args:
        string: The input string to process

    Returns:
        A new string with case flipped for each alphabetic character
    """
    result = []
    for char in string:
        if char.islower():
            result.append(char.upper())
        elif char.isupper():
            result.append(char.lower())
        else:
            result.append(char)  # Non-alphabetic characters remain unchanged
    return ''.join(result)
```

