```python
def fib4(n: int) -> int:
    # Handle base cases
    if n == 0:
        return 0
    elif n == 1:
        return 0
    elif n == 2:
        return 2
    elif n == 3:
        return 0

    # Initialize the first four values
    a, b, c, d = 0, 0, 2, 0  # fib4(0), fib4(1), fib4(2), fib4(3)

    # Iterate from 4 to n, updating the four previous values
    for i in range(4, n + 1):
        next_val = a + b + c + d
        # Shift all values: a becomes b, b becomes c, c becomes d, d becomes next_val
        a, b, c, d = b, c, d, next_val

    return d
```

```python
def fib(n: int) -> int:
    if n <= 0:
        return 0
    elif n == 1:
        return 1

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b
```

```python
from typing import List

def rolling_max(numbers: List[int]) -> List[int]:
    if not numbers:
        return []

    result = []
    current_max = numbers[0]

    for num in numbers:
        if num > current_max:
            current_max = num
        result.append(current_max)

    return result
```

